use std::error::Error;
use std::fmt;

struct DataMatrix(Vec<Vec<f64>>);

impl DataMatrix {
    fn new(data: Vec<Vec<f64>>) -> Self {
        DataMatrix(data)
    }

    fn filter_columns_by_mean_range(&self, min_mean: f64, max_mean: f64) -> Result<Self, Box<dyn Error>> {
        if self.0.is_empty() || self.0[0].is_empty() {
            return Ok(DataMatrix(vec![]));
        }

        let num_columns = self.0[0].len();
        let mut column_means: Vec<f64> = Vec::with_capacity(num_columns);

        for j in 0..num_columns {
            let mut sum: f64 = 0.0;
            for i in 0..self.0.len() {
                sum += self.0[i][j];
            }
            column_means.push(sum / (self.0.len() as f64));
        }

        let mut filtered_data: Vec<Vec<f64>> = Vec::new();

        for row in self.0.iter() {
            let mut new_row: Vec<f64> = Vec::new();
            for j in 0..num_columns {
                if column_means[j] >= min_mean && column_means[j] <= max_mean {
                    new_row.push(row[j]);
                }
            }
            filtered_data.push(new_row);
        }

        Ok(DataMatrix(filtered_data))
    }
}

fn main() -> Result<(), Box<dyn Error>> {
    let raw_data: Vec<Vec<f64>> = vec![ 
        vec![1.0, 5.0, 2.0], 
        vec![2.0, 3.0, 8.0], 
        vec![3.0, 7.0, 1.0] 
    ];

    let matrix = DataMatrix::new(raw_data);

    let min_m = 3.0;
    let max_m = 5.5;

    match matrix.filter_columns_by_mean_range(min_m, max_m) {
        Ok(result_matrix) => {
            println!("Filtered Matrix Rows:");
            for row in result_matrix.0.iter() {
                println!("{:?}", row);
            }
        },
        Err(e) => {
            eprintln!("Error processing matrix: {}", e);
        }
    }
    Ok(())
}

use std::collections::VecDeque;
use std::fs;
use std::io::{self, Result};

struct FileSearcher {
    queue: VecDeque<String>,
}

impl FileSearcher {
    fn new(initial_paths: Vec<String>) -> Self {
        let mut queue = VecDeque::new();
        for path in initial_paths {
            queue.push_back(path);
        }
        FileSearcher { queue }
    }

    fn process_directory(&mut self) -> io::Result<()> {
        if let Some(current_dir) = self.queue.pop_front() {
            println!("Processing directory: {}", current_dir);
            match fs::read_dir(&current_dir) {
                Ok(entries) => {
                    for entry in entries {
                        let entry = entry?;
                        let path = entry.path();
                        if path.is_dir() {
                            self.queue.push_back(path.to_string_lossy().into_owned());
                        } else if path.is_file() {
                            println!("Found file: {}", path.display());
                        }
                    }
                }
                Err(e) => {
                    eprintln!("Could not read directory {}: {}", current_dir, e);
                }
            }
        }
        Ok(())
    }
}

fn main() -> io::Result<()> {
    let start_path = ".".to_string();
    let mut searcher = FileSearcher::new(vec![start_path]);

    loop {
        match searcher.process_directory() {
            Ok(()) => continue,
            Err(_) => break,
        }
    }

    Ok(())
}

use std::collections::VecDeque;

struct ConnectionRequest {
    id: u32,
    data_size: usize,
}

fn process_requests(initial_requests: Vec<ConnectionRequest>) -> Vec<String> {
    let mut processed_results = Vec::with_capacity(initial_requests.len());

    for request in initial_requests.into_iter() {
        if request.data_size > 0 {
            let result = format!("Successfully handled request ID {} with data size {}", request.id, request.data_size);
            processed_results.push(result);
        } else {
            processed_results.push(format!("Skipped request ID {} due to zero data size", request.id));
        }
    }
    processed_results
}

use std::fs::File;
use std::io::{self, Write};

struct PhotoRecord {
    original_path: String,
    date_str: String,
    base_name: String,
}

fn process_photos(records: Vec<PhotoRecord>) -> io::Result<()> {
    let mut new_files = Vec::new();
    for record in records.into_iter() {
        let formatted_name = format!("{}-{}.jpg", &record.date_str, &record.base_name);
        new_files.push(formatted_name);
    }

    println!("Successfully generated {} new filenames.", new_files.len());
    for filename in new_files {
        println!("  - {}", filename);
    }

    Ok(())
}

fn main() -> io::Result<()> {
    let records = vec![ 
        PhotoRecord { original_path: "img1.raw".to_string(), date_str: "2023-10-01".to_string(), base_name: "vacation".to_string() },
        PhotoRecord { original_path: "img2.raw".to_string(), date_str: "2023-10-05".to_string(), base_name: "beach".to_string() },
        PhotoRecord { original_path: "img3.raw".to_string(), date_str: "2023-10-01".to_string(), base_name: "family".to_string() },
    ];
    process_photos(records)
}

use std::collections::HashSet;
use std::io::{self, Write};

struct SourceMapGenerator {
    file_paths: Vec<String>,
}

impl SourceMapGenerator {
    fn new(paths: Vec<String>) -> Self {
        SourceMapGenerator { file_paths: paths }
    }

    fn generate_unique_list(&self) -> HashSet<String> {
        let mut unique_set = HashSet::new();
        for path in &self.file_paths {
            if !path.is_empty() {
                unique_set.insert(path.clone());
            }
        }
        unique_set
    }

    fn write_map(&self, unique_paths: HashSet<String>) -> io::Result<()> {
        let mut file = std::fs::File::create("source_map.txt")?;
        for path in unique_paths {
            writeln!(file, "Source Path: {}", path)?;
        }
        Ok(())
    }
}

fn main() -> io::Result<()> {
    let initial_files = vec!["src/app.js".to_string(), "utils/helper.js".to_string(), "src/app.js".to_string()];
    let generator = SourceMapGenerator::new(initial_files);

    let unique_paths = generator.generate_unique_list();

    if let Err(e) = generator.write_map(unique_paths) {
        eprintln!("Error writing map: {}", e);
    }
    Ok(())
}
